const now = new Date();
const month = now.getMonth() + 1;
const day = now.getDate();

// 계절 판단
let season = '';
let seasonDesc = '';
if (month >= 3 && month <= 5) { season = '봄'; seasonDesc = '졸업/입학 시즌, 벚꽃 행사, 신학기'; }
else if (month >= 6 && month <= 8) { season = '여름'; seasonDesc = '워터파크, 야외 행사, 여름 축제, 체육대회'; }
else if (month >= 9 && month <= 11) { season = '가을'; seasonDesc = '운동회, 추석 명절, 기업 행사, 송년회 준비'; }
else { season = '겨울'; seasonDesc = '연말 송년회, 크리스마스, 신년 선물, 설 명절'; }

// 특수 시즌
const specialEvents = [];
if (month === 2 || month === 3) specialEvents.push('졸업/입학 시즌');
if (month === 5) specialEvents.push('어린이날, 스승의날, 가정의달');
if (month === 9 || month === 10) specialEvents.push('추석 명절, 체육대회');
if (month === 12 || month === 1) specialEvents.push('연말연시, 신년');

return [{ json: {
  month, day, season, seasonDesc,
  specialEvents: specialEvents.join(', ') || '일반 시즌',
  dateStr: `${month}월 ${day}일`
} }];

const d = $input.first().json;
let raw = '';
if (d.candidates && d.candidates[0]) raw = d.candidates[0]?.content?.parts?.[0]?.text || '';
raw = raw.replace(/```json\s*/g, '').replace(/```\s*/g, '').trim();

let parsed;
try { parsed = JSON.parse(raw); } catch(e) { parsed = { season: '현재', products: [] }; }

const products = parsed.products || [];

// 폼 옵션 생성
const formOptions = products.map(p => `${p.rank}위. ${p.name} - ${p.reason.slice(0, 50)}`);

// 추천 요약 텍스트
const summaryLines = products.map(p =>
  `${p.rank}위. ${p.name}\n   카테고리: ${p.category}\n   추천이유: ${p.reason}\n   타겟: ${p.target}`
);

return [{ json: {
  season: parsed.season,
  products,
  formOptions,
  summary: summaryLines.join('\n\n'),
  rawJson: JSON.stringify(products)
} }];

const formData = $input.first().json;
const prevData = $('추천 목록 파싱').first().json;

// 선택된 옵션에서 순위 추출
const selected = formData['추천 제품 선택'] || '';
const rankMatch = selected.match(/^(\d+)위\.\s*(.+?)\s*-/);
const rank = rankMatch ? parseInt(rankMatch[1]) : 1;

// 해당 제품 정보 찾기
const products = prevData.products || [];
const product = products.find(p => p.rank === rank) || products[0] || {};

const today = new Date().toISOString().slice(0, 10);

return [{ json: {
  product_name: product.name || selected,
  category: product.category || '',
  reason: product.reason || '',
  target: product.target || '',
  keywords: product.keywords || '',
  season: prevData.season || '',
  product_url: formData['제품 URL (비즈메카 링크)'] || '',
  extra_request: formData['추가 요청사항'] || '없음',
  date: today
} }];

const d = $input.first().json;

const lines = [
  '너는 판촉물·홍보물 전문 납품업체 DCT컴퍼니의 블로그 마케터야.',
  '아래 제품 정보를 바탕으로 네이버 블로그용 제품소개 포스팅을 작성해줘.',
  '',
  '## 제품 정보',
  '제품명: ' + d.product_name,
  '카테고리: ' + d.category,
  '시즌: ' + d.season,
  '추천이유/트렌드: ' + d.reason,
  '주요타겟: ' + d.target,
  '관련키워드: ' + d.keywords,
  '추가요청: ' + d.extra_request,
  '',
  '## 작성 규칙',
  '1. 제목: SEO 최적화 제목 (예: [제품소개] OO 시즌 필수 판촉물 추천!)',
  '2. 본문: 500~700자, 친근하고 전문적인 톤',
  '3. 구성: 인사말 → 시즌 트렌드 소개 → 제품 특징 → 활용 사례 → 구매 안내 → 마무리',
  '4. 해시태그: 10~15개',
  '5. JSON 형식으로만 응답 (백틱 없이): {"title":"...","body":"...","hashtags":"..."}'
];

const requestBody = {
  contents: [{ parts: [{ text: lines.join('\n') }] }],
  generationConfig: { temperature: 0.7, maxOutputTokens: 2000 }
};

return [{ json: { ...d, gemini_body: JSON.stringify(requestBody) } }];

const d = $input.first().json;
const prev = $('블로그 프롬프트 조립').first().json;

let raw = '';
if (d.candidates && d.candidates[0]) raw = d.candidates[0]?.content?.parts?.[0]?.text || '';
raw = raw.replace(/```json\s*/g, '').replace(/```\s*/g, '').trim();

let title = '', body = '', hashtags = '';
try {
  const p = JSON.parse(raw);
  title = p.title || '';
  body = p.body || raw;
  hashtags = p.hashtags || '';
} catch(e) {
  title = '[제품소개] ' + prev.product_name + ' - 수동편집 필요';
  body = raw;
  hashtags = '#판촉물 #홍보물 #DCT컴퍼니';
}

return [{ json: { ...prev, title, body, hashtags } }];

const d = $input.first().json;
const prev = $('심화 프롬프트 조립').first().json;

let raw = '';
if (d.candidates && d.candidates[0]) raw = d.candidates[0]?.content?.parts?.[0]?.text || '';
raw = raw.replace(/```json\s*/g, '').replace(/```\s*/g, '').trim();

let title = prev.title, body = raw, hashtags = prev.hashtags;
try {
  const p = JSON.parse(raw);
  title = p.title || prev.title;
  body = p.body || raw;
  hashtags = p.hashtags || prev.hashtags;
} catch(e) {}

return [{ json: { ...prev, title_enhanced: title, body_enhanced: body, hashtags_enhanced: hashtags } }];
